// Generated by Claude Sonnet 4.5

import { BackupStatus } from '@eclipse-che/common';
import mockAxios from 'axios';

import { getWorkspaceBackupStatus, listBackups } from '@/services/backend-client/backupApi';

describe('Backup API', () => {
  const mockGet = mockAxios.get as jest.Mock;

  const namespace = 'user-che';
  const workspaceName = 'my-workspace';
  const imageUrl = 'image-registry.openshift-image-registry.svc:5000/user-che/my-workspace:latest';

  afterEach(() => {
    jest.resetAllMocks();
  });

  describe('getWorkspaceBackupStatus', () => {
    it('should fetch backup status with SUCCESS state', async () => {
      const mockBackupInfo = {
        status: BackupStatus.SUCCESS,
        lastBackupTime: '2026-02-10T12:00:00.000Z',
        backupSchedule: '0 1 * * *',
        backupImageUrl: imageUrl,
        sizeBytes: 1024000,
      };

      mockGet.mockResolvedValueOnce({ data: mockBackupInfo });

      const result = await getWorkspaceBackupStatus(namespace, workspaceName);

      expect(mockGet).toHaveBeenCalled();
      expect(mockGet.mock.calls[0][0]).toBe(
        `/dashboard/api/namespace/${namespace}/devworkspaces/${workspaceName}/backup-status`,
      );
      expect(result).toEqual(mockBackupInfo);
      expect(result.status).toBe(BackupStatus.SUCCESS);
    });

    it('should fetch backup status with NEVER state', async () => {
      const mockBackupInfo = {
        status: BackupStatus.NEVER,
        backupSchedule: '0 1 * * *',
      };

      mockGet.mockResolvedValueOnce({ data: mockBackupInfo });

      const result = await getWorkspaceBackupStatus(namespace, workspaceName);

      expect(result.status).toBe(BackupStatus.NEVER);
      expect(result.lastBackupTime).toBeUndefined();
      expect(result.backupImageUrl).toBeUndefined();
    });

    it('should fetch backup status with IN_PROGRESS state', async () => {
      const mockBackupInfo = {
        status: BackupStatus.IN_PROGRESS,
        lastBackupTime: '2026-02-10T12:00:00.000Z',
        backupSchedule: '0 1 * * *',
        backupImageUrl: imageUrl,
      };

      mockGet.mockResolvedValueOnce({ data: mockBackupInfo });

      const result = await getWorkspaceBackupStatus(namespace, workspaceName);

      expect(result.status).toBe(BackupStatus.IN_PROGRESS);
    });

    it('should fetch backup status with FAILED state', async () => {
      const mockBackupInfo = {
        status: BackupStatus.FAILED,
        lastBackupTime: '2026-02-10T12:00:00.000Z',
        backupSchedule: '0 1 * * *',
        error: 'Backup job failed: insufficient storage',
      };

      mockGet.mockResolvedValueOnce({ data: mockBackupInfo });

      const result = await getWorkspaceBackupStatus(namespace, workspaceName);

      expect(result.status).toBe(BackupStatus.FAILED);
      expect(result.error).toContain('insufficient storage');
    });

    it('should throw error when API call fails', async () => {
      const errorMessage = 'Workspace not found';
      mockGet.mockRejectedValueOnce(new Error(errorMessage));

      await expect(getWorkspaceBackupStatus(namespace, workspaceName)).rejects.toThrow(
        `Failed to fetch backup status for workspace '${workspaceName}'`,
      );
    });
  });

  describe('listBackups', () => {
    it('should list all backups in namespace without filters', async () => {
      const mockResponse = [
        {
          workspaceName: 'workspace-1',
          imageUrl: 'image-registry.openshift-image-registry.svc:5000/user-che/workspace-1:latest',
          timestamp: '2026-02-10T12:00:00.000Z',
          sizeBytes: 1024000,
          workspaceExists: true,
          labels: {},
        },
        {
          workspaceName: 'workspace-2',
          imageUrl: 'image-registry.openshift-image-registry.svc:5000/user-che/workspace-2:latest',
          timestamp: '2026-02-09T12:00:00.000Z',
          sizeBytes: 2048000,
          workspaceExists: false,
          labels: {},
        },
      ];

      mockGet.mockResolvedValueOnce({ data: mockResponse });

      const result = await listBackups(namespace);

      expect(mockGet).toHaveBeenCalledWith(`/dashboard/api/namespace/${namespace}/backups`, {
        params: {
          workspaceName: undefined,
        },
      });
      expect(result).toEqual(mockResponse);
      expect(result).toHaveLength(2);
    });

    it('should list backups with workspace name filter', async () => {
      const mockResponse = [
        {
          workspaceName,
          imageUrl,
          timestamp: '2026-02-10T12:00:00.000Z',
          sizeBytes: 1024000,
          workspaceExists: true,
          labels: {},
        },
      ];

      mockGet.mockResolvedValueOnce({ data: mockResponse });

      const result = await listBackups(namespace, workspaceName);

      expect(mockGet).toHaveBeenCalledWith(`/dashboard/api/namespace/${namespace}/backups`, {
        params: {
          workspaceName,
        },
      });
      expect(result).toHaveLength(1);
      expect(result[0].workspaceName).toBe(workspaceName);
    });

    it('should return empty list when no backups exist', async () => {
      mockGet.mockResolvedValueOnce({ data: [] });

      const result = await listBackups(namespace);

      expect(result).toHaveLength(0);
    });

    it('should throw error when API call fails', async () => {
      const errorMessage = 'Namespace not found';
      mockGet.mockRejectedValueOnce(new Error(errorMessage));

      await expect(listBackups(namespace)).rejects.toThrow(
        `Failed to list backups for namespace '${namespace}'`,
      );
    });
  });
});
